   905έΗΤ## 4.2.7 Route Utilization Service (NEW v2.1)
   906έΗΤ
   907έΗΤ### 4.2.7.1 Purpose
   908έΗΤ
   909έΗΤProvide route-specific daily mileage rates for accurate long-term projections. Using fleet-wide averages can result in 60,000+ km projection error over 12 years.
   910έΗΤ
   911έΗΤ### 4.2.7.2 Implementation
   912έΗΤ
   913έΗΤ```typescript
   914έΗΤinterface RouteUtilizationProfile {
   915έΗΤ  id: string;
   916έΗΤ  routeId: string;
   917έΗΤ  effectiveDate: Date;
   918έΗΤ  
   919έΗΤ  weekdayKm: number;
   920έΗΤ  saturdayKm?: number;
   921έΗΤ  sundayKm?: number;
   922έΗΤ  holidayKm?: number;
   923έΗΤ  
   924έΗΤ  peakSeasonMultiplier: number;
   925έΗΤ  offPeakMultiplier: number;
   926έΗΤ  
   927έΗΤ  confidence: 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
   928έΗΤ}
   929έΗΤ
   930έΗΤclass RouteUtilizationService {
   931έΗΤ  constructor(private db: Database) {}
   932έΗΤ  
   933έΗΤ  /**
   934έΗΤ   * Get utilization profile for a route
   935έΗΤ   */
   936έΗΤ  async getProfile(routeId: string, asOfDate?: Date): Promise<RouteUtilizationProfile | null> {
   937έΗΤ    const date = asOfDate || new Date();
   938έΗΤ    
   939έΗΤ    const profile = await this.db
   940έΗΤ      .select()
   941έΗΤ      .from(routeUtilizationProfiles)
   942έΗΤ      .where(and(
   943έΗΤ        eq(routeUtilizationProfiles.routeId, routeId),
   944έΗΤ        lte(routeUtilizationProfiles.effectiveDate, date)
   945έΗΤ      ))
   946έΗΤ      .orderBy(desc(routeUtilizationProfiles.effectiveDate))
   947έΗΤ      .limit(1);
   948έΗΤ    
   949έΗΤ    return profile[0] || null;
   950έΗΤ  }
   951έΗΤ  
   952έΗΤ  /**
   953έΗΤ   * Calculate expected daily km for a train based on typical route assignment
   954έΗΤ   */
   955έΗΤ  async calculateDailyRate(
   956έΗΤ    trainId: string, 
   957έΗΤ    targetDate: Date
   958έΗΤ  ): Promise<{ dailyKm: number; source: string; confidence: string }> {
   959έΗΤ    // 1. Check for explicit route assignment
   960έΗΤ    const assignment = await this.getTypicalRouteAssignment(trainId);
   961έΗΤ    
   962έΗΤ    if (assignment) {
   963έΗΤ      const profile = await this.getProfile(assignment.routeId, targetDate);
   964έΗΤ      if (profile) {
   965έΗΤ        const dayType = this.getDayType(targetDate);
   966έΗΤ        const baseKm = this.getKmForDayType(profile, dayType);
   967έΗΤ        const seasonalMultiplier = this.getSeasonalMultiplier(profile, targetDate);
   968έΗΤ        
   969έΗΤ        return {
   970έΗΤ          dailyKm: Math.round(baseKm * seasonalMultiplier),
   971έΗΤ          source: `route:${assignment.routeId}`,
   972έΗΤ          confidence: profile.confidence
   973έΗΤ        };
   974έΗΤ      }
   975έΗΤ    }
   976έΗΤ    
   977έΗΤ    // 2. Fall back to fleet average
   978έΗΤ    const train = await this.db
   979έΗΤ      .select({ fleetId: trains.fleetId })
   980έΗΤ      .from(trains)
   981έΗΤ      .where(eq(trains.id, trainId))
   982έΗΤ      .limit(1);
   983έΗΤ    
   984έΗΤ    if (train[0]) {
   985έΗΤ      const fleetAverage = await this.getFleetAverage(train[0].fleetId);
   986έΗΤ      return {
   987έΗΤ        dailyKm: fleetAverage,
   988έΗΤ        source: 'fleet_average',
   989έΗΤ        confidence: 'LOW'
   990έΗΤ      };
   991έΗΤ    }
   992έΗΤ    
   993έΗΤ    // 3. System default
   994έΗΤ    return {
   995έΗΤ      dailyKm: 250,  // Conservative default
   996έΗΤ      source: 'system_default',
   997έΗΤ      confidence: 'ESTIMATED'
   998έΗΤ    };
   999έΗΤ  }
  1000έΗΤ  
  1001έΗΤ  /**
  1002έΗΤ   * Project mileage for a train over a time horizon
  1003έΗΤ   */
  1004έΗΤ  async projectMileage(
  1005έΗΤ    trainId: string,
  1006έΗΤ    startDate: Date,
  1007έΗΤ    horizonDays: number
  1008έΗΤ  ): Promise<{ date: Date; projectedKm: number; cumulativeKm: number }[]> {
  1009έΗΤ    const train = await this.db
  1010έΗΤ      .select()
  1011έΗΤ      .from(trains)
  1012έΗΤ      .where(eq(trains.id, trainId))
  1013έΗΤ      .limit(1);
  1014έΗΤ    
  1015έΗΤ    if (!train[0]) {
  1016έΗΤ      throw new NotFoundError(`Train ${trainId} not found`);
  1017έΗΤ    }
  1018έΗΤ    
  1019έΗΤ    let cumulativeKm = train[0].currentMileageKm;
  1020έΗΤ    const projections: { date: Date; projectedKm: number; cumulativeKm: number }[] = [];
  1021έΗΤ    
  1022έΗΤ    for (let day = 0; day < horizonDays; day++) {
  1023έΗΤ      const targetDate = addDays(startDate, day);
  1024έΗΤ      const { dailyKm } = await this.calculateDailyRate(trainId, targetDate);
  1025έΗΤ      
  1026έΗΤ      cumulativeKm += dailyKm;
  1027έΗΤ      projections.push({
  1028έΗΤ        date: targetDate,
  1029έΗΤ        projectedKm: dailyKm,
  1030έΗΤ        cumulativeKm
  1031έΗΤ      });
  1032έΗΤ    }
  1033έΗΤ    
  1034έΗΤ    return projections;
  1035έΗΤ  }
  1036έΗΤ  
  1037έΗΤ  private async getTypicalRouteAssignment(trainId: string): Promise<{ routeId: string } | null> {
  1038έΗΤ    // Look at recent run assignments to determine typical route
  1039έΗΤ    const recentAssignments = await this.db
  1040έΗΤ      .select({ routeId: runAssignments.routeId, count: count() })
  1041έΗΤ      .from(runAssignments)
  1042έΗΤ      .where(and(
  1043έΗΤ        eq(runAssignments.trainId, trainId),
  1044έΗΤ        gte(runAssignments.assignmentDate, addDays(new Date(), -30))
  1045έΗΤ      ))
  1046έΗΤ      .groupBy(runAssignments.routeId)
  1047έΗΤ      .orderBy(desc(count()))
  1048έΗΤ      .limit(1);
  1049έΗΤ    
  1050έΗΤ    return recentAssignments[0] || null;
  1051έΗΤ  }
  1052έΗΤ  
  1053έΗΤ  private async getFleetAverage(fleetId: string): Promise<number> {
  1054έΗΤ    // Calculate from recent mileage readings
  1055έΗΤ    const result = await this.db
  1056έΗΤ      .select({ avgDaily: avg(mileageReadings.dailyKm) })
  1057έΗΤ      .from(mileageReadings)
  1058έΗΤ      .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
  1059έΗΤ      .where(and(
  1060έΗΤ        eq(trains.fleetId, fleetId),
  1061έΗΤ        gte(mileageReadings.readingDate, addDays(new Date(), -30)),
  1062έΗΤ        eq(mileageReadings.validationStatus, 'VALID')
  1063έΗΤ      ));
  1064έΗΤ    
  1065έΗΤ    return Math.round(result[0]?.avgDaily || 250);
  1066έΗΤ  }
  1067έΗΤ  
  1068έΗΤ  private getKmForDayType(profile: RouteUtilizationProfile, dayType: string): number {
  1069έΗΤ    switch (dayType) {
  1070έΗΤ      case 'SATURDAY': return profile.saturdayKm || profile.weekdayKm * 0.8;
  1071έΗΤ      case 'SUNDAY': return profile.sundayKm || profile.weekdayKm * 0.7;
  1072έΗΤ      case 'HOLIDAY': return profile.holidayKm || profile.weekdayKm * 0.6;
  1073έΗΤ      default: return profile.weekdayKm;
  1074έΗΤ    }
  1075έΗΤ  }
  1076έΗΤ  
  1077έΗΤ  private getSeasonalMultiplier(profile: RouteUtilizationProfile, date: Date): number {
  1078έΗΤ    // TODO: Integrate with season calendar
  1079έΗΤ    const month = date.getMonth();
  1080έΗΤ    // Peak season: CNY (Jan-Feb), School holidays (Jun, Nov-Dec)
  1081έΗΤ    const peakMonths = [0, 1, 5, 10, 11];
  1082έΗΤ    return peakMonths.includes(month) ? profile.peakSeasonMultiplier : profile.offPeakMultiplier;
  1083έΗΤ  }
  1084έΗΤ  
  1085έΗΤ  private getDayType(date: Date): string {
  1086έΗΤ    const dayOfWeek = date.getDay();
  1087έΗΤ    if (dayOfWeek === 0) return 'SUNDAY';
  1088έΗΤ    if (dayOfWeek === 6) return 'SATURDAY';
  1089έΗΤ    return 'WEEKDAY';
  1090έΗΤ  }
  1091έΗΤ}
