  1096έΗΤ## 4.3 Run Assignment Optimizer
  1097έΗΤ
  1098έΗΤ### 4.3.1 Purpose
  1099έΗΤ
  1100έΗΤOptimize daily train-to-route assignments for mileage balancing while respecting hard constraints (fitness, PM due, **unavailability**, **service demand**) and minimizing soft constraint penalties.
  1101έΗΤ
  1102έΗΤ### 4.3.2 Optimizer Service (TypeScript Wrapper)
  1103έΗΤ
  1104έΗΤ```typescript
  1105έΗΤinterface OptimizerConfig {
  1106έΗΤ  binaryPath: string;          // ./mms-optimizer
  1107έΗΤ  maxSolveTimeSeconds: number; // 30
  1108έΗΤ  numWorkers: number;          // 4
  1109έΗΤ  timeoutMs: number;           // 60000
  1110έΗΤ  fallbackEnabled: boolean;    // true
  1111έΗΤ}
  1112έΗΤ
  1113έΗΤclass RunAssignmentOptimizer {
  1114έΗΤ  private process: Subprocess | null = null;
  1115έΗΤ  
  1116έΗΤ  async optimize(input: OptimizerInput): Promise<OptimizerResult> {
  1117έΗΤ    const startTime = Date.now();
  1118έΗΤ    
  1119έΗΤ    try {
  1120έΗΤ      // Try C++ optimizer first
  1121έΗΤ      const result = await this.runCppOptimizer(input);
  1122έΗΤ      
  1123έΗΤ      // Validate result
  1124έΗΤ      if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
  1125έΗΤ        this.logger.warn('C++ optimizer returned INFEASIBLE, using fallback');
  1126έΗΤ        return await this.runFallbackOptimizer(input);
  1127έΗΤ      }
  1128έΗΤ      
  1129έΗΤ      return result;
  1130έΗΤ      
  1131έΗΤ    } catch (error) {
  1132έΗΤ      this.logger.error({ error }, 'C++ optimizer failed, using fallback');
  1133έΗΤ      
  1134έΗΤ      if (this.config.fallbackEnabled) {
  1135έΗΤ        return await this.runFallbackOptimizer(input);
  1136έΗΤ      }
  1137έΗΤ      
  1138έΗΤ      throw error;
  1139έΗΤ    }
  1140έΗΤ  }
  1141έΗΤ  
  1142έΗΤ  private async runCppOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1143έΗΤ    return new Promise((resolve, reject) => {
  1144έΗΤ      const timeout = setTimeout(() => {
  1145έΗΤ        this.process?.kill();
  1146έΗΤ        reject(new Error('Optimizer timeout'));
  1147έΗΤ      }, this.config.timeoutMs);
  1148έΗΤ      
  1149έΗΤ      this.process = Bun.spawn([this.config.binaryPath], {
  1150έΗΤ        stdin: 'pipe',
  1151έΗΤ        stdout: 'pipe',
  1152έΗΤ        stderr: 'pipe'
  1153έΗΤ      });
  1154έΗΤ      
  1155έΗΤ      // Write input
  1156έΗΤ      const writer = this.process.stdin.getWriter();
  1157έΗΤ      writer.write(new TextEncoder().encode(JSON.stringify(input) + '\n'));
  1158έΗΤ      writer.close();
  1159έΗΤ      
  1160έΗΤ      // Read stdout (results)
  1161έΗΤ      const results: any[] = [];
  1162έΗΤ      const reader = this.process.stdout.getReader();
  1163έΗΤ      const decoder = new TextDecoder();
  1164έΗΤ      let buffer = '';
  1165έΗΤ      
  1166έΗΤ      const readStream = async () => {
  1167έΗΤ        while (true) {
  1168έΗΤ          const { done, value } = await reader.read();
  1169έΗΤ          if (done) break;
  1170έΗΤ          
  1171έΗΤ          buffer += decoder.decode(value, { stream: true });
  1172έΗΤ          const lines = buffer.split('\n');
  1173έΗΤ          buffer = lines.pop() || '';
  1174έΗΤ          
  1175έΗΤ          for (const line of lines) {
  1176έΗΤ            if (!line.trim()) continue;
  1177έΗΤ            
  1178έΗΤ            try {
  1179έΗΤ              const msg = JSON.parse(line);
  1180έΗΤ              
  1181έΗΤ              if (msg.type === 'PROGRESS') {
  1182έΗΤ                this.emitProgress(msg);
  1183έΗΤ              } else if (msg.type === 'RESULT') {
  1184έΗΤ                clearTimeout(timeout);
  1185έΗΤ                resolve(this.mapResult(msg));
  1186έΗΤ                return;
  1187έΗΤ              }
  1188έΗΤ            } catch (e) {
  1189έΗΤ              this.logger.warn({ line }, 'Failed to parse optimizer output');
  1190έΗΤ            }
  1191έΗΤ          }
  1192έΗΤ        }
  1193έΗΤ      };
  1194έΗΤ      
  1195έΗΤ      // Read stderr (metrics/logs)
  1196έΗΤ      this.readStderr(this.process.stderr);
  1197έΗΤ      
  1198έΗΤ      readStream().catch(reject);
  1199έΗΤ      
  1200έΗΤ      this.process.exited.then((code) => {
  1201έΗΤ        clearTimeout(timeout);
  1202έΗΤ        if (code !== 0 && results.length === 0) {
  1203έΗΤ          reject(new Error(`Optimizer exited with code ${code}`));
  1204έΗΤ        }
  1205έΗΤ      });
  1206έΗΤ    });
  1207έΗΤ  }
  1208έΗΤ  
  1209έΗΤ  private async runFallbackOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1210έΗΤ    // TypeScript greedy fallback
  1211έΗΤ    const assignments: Assignment[] = [];
  1212έΗΤ    const unassigned: UnassignedTrain[] = [];
  1213έΗΤ    const assignedTrainIds = new Set<string>();
  1214έΗΤ    
  1215έΗΤ    // Sort routes by priority (required trains desc)
  1216έΗΤ    const sortedRoutes = [...input.routes].sort(
  1217έΗΤ      (a, b) => b.required_trains - a.required_trains
  1218έΗΤ    );
  1219έΗΤ    
  1220έΗΤ    // Sort trains by fitness and mileage balance
  1221έΗΤ    const sortedTrains = [...input.trains]
  1222έΗΤ      .filter(t => t.fitness_status === 'FIT')
  1223έΗΤ      .sort((a, b) => {
  1224έΗΤ        // Prioritize under-utilized trains
  1225έΗΤ        const aBalance = a.current_mileage - a.target_mileage;
  1226έΗΤ        const bBalance = b.current_mileage - b.target_mileage;
  1227έΗΤ        return aBalance - bBalance;
  1228έΗΤ      });
  1229έΗΤ    
  1230έΗΤ    for (const route of sortedRoutes) {
  1231έΗΤ      let assigned = 0;
  1232έΗΤ      
  1233έΗΤ      for (const train of sortedTrains) {
  1234έΗΤ        if (assigned >= route.required_trains) break;
  1235έΗΤ        if (assignedTrainIds.has(train.id)) continue;
  1236έΗΤ        
  1237έΗΤ        // Check hard constraints
  1238έΗΤ        const hardViolation = this.checkHardConstraints(train, route, input);
  1239έΗΤ        if (hardViolation) {
  1240έΗΤ          continue;
  1241έΗΤ        }
  1242έΗΤ        
  1243έΗΤ        // Check fleet compatibility
  1244έΗΤ        if (route.allowed_fleets.length > 0 && 
  1245έΗΤ            !route.allowed_fleets.includes(train.fleet_id)) {
  1246έΗΤ          continue;
  1247έΗΤ        }
  1248έΗΤ        
  1249έΗΤ        // Assign
  1250έΗΤ        assignments.push({
  1251έΗΤ          train_id: train.id,
  1252έΗΤ          route_id: route.id,
  1253έΗΤ          score: this.calculateScore(train, route),
  1254έΗΤ          explanation: [
  1255έΗΤ            {
  1256έΗΤ              constraint_type: 'SOFT',
  1257έΗΤ              constraint_name: 'MILEAGE_BALANCE',
  1258έΗΤ              impact: train.current_mileage - train.target_mileage,
  1259έΗΤ              description: `Train is ${Math.abs(train.current_mileage - train.target_mileage)}km ${
  1260έΗΤ                train.current_mileage < train.target_mileage ? 'under' : 'over'
  1261έΗΤ              } target`
  1262έΗΤ            }
  1263έΗΤ          ]
  1264έΗΤ        });
  1265έΗΤ        
  1266έΗΤ        assignedTrainIds.add(train.id);
  1267έΗΤ        assigned++;
  1268έΗΤ      }
  1269έΗΤ      
  1270έΗΤ      // Record shortfall
  1271έΗΤ      if (assigned < route.required_trains) {
  1272έΗΤ        unassigned.push({
  1273έΗΤ          route_id: route.id,
  1274έΗΤ          shortfall: route.required_trains - assigned,
  1275έΗΤ          reason: 'Insufficient fit trains available'
  1276έΗΤ        });
  1277έΗΤ      }
  1278έΗΤ    }
  1279έΗΤ    
  1280έΗΤ    // Record unassigned trains with reasons
  1281έΗΤ    for (const train of input.trains) {
  1282έΗΤ      if (assignedTrainIds.has(train.id)) continue;
  1283έΗΤ      
  1284έΗΤ      const reason = train.fitness_status !== 'FIT' 
  1285έΗΤ        ? `Train is ${train.fitness_status}`
  1286έΗΤ        : this.findBlockingConstraint(train, input);
  1287έΗΤ      
  1288έΗΤ      unassigned.push({
  1289έΗΤ        train_id: train.id,
  1290έΗΤ        reason,
  1291έΗΤ        blocking_constraints: this.getBlockingConstraints(train, input)
  1292έΗΤ      });
  1293έΗΤ    }
  1294έΗΤ    
  1295έΗΤ    return {
  1296έΗΤ      type: 'RESULT',
  1297έΗΤ      request_id: input.request_id,
  1298έΗΤ      status: 'FALLBACK',
  1299έΗΤ      solve_time_ms: 0,
  1300έΗΤ      assignments,
  1301έΗΤ      unassigned,
  1302έΗΤ      material_warnings: [],
  1303έΗΤ      summary: {
  1304έΗΤ        total_penalty: 1e6,  // High penalty for fallback
  1305έΗΤ        trains_assigned: assignments.length,
  1306έΗΤ        trains_unassigned: unassigned.length,
  1307έΗΤ        soft_constraint_breakdown: {},
  1308έΗΤ        material_blocks: 0
  1309έΗΤ      }
  1310έΗΤ    };
  1311έΗΤ  }
  1312έΗΤ  
  1313έΗΤ  private checkHardConstraints(
  1314έΗΤ    train: Train,
  1315έΗΤ    route: Route,
  1316έΗΤ    input: OptimizerInput
  1317έΗΤ  ): string | null {
  1318έΗΤ    // NEW v2.1: Check unavailability events first
  1319έΗΤ    if (input.unavailability_events) {
  1320έΗΤ      for (const event of input.unavailability_events) {
  1321έΗΤ        if (event.train_id === train.id && 
  1322έΗΤ            event.status === 'ACTIVE' && 
  1323έΗΤ            event.blocks_run_assignment) {
  1324έΗΤ          return `Train unavailable: ${event.event_type} - ${event.description || event.external_reference || 'No details'}`;
  1325έΗΤ        }
  1326έΗΤ      }
  1327έΗΤ    }
  1328έΗΤ    
  1329έΗΤ    // Check explicit hard constraints
  1330έΗΤ    for (const constraint of input.hard_constraints) {
  1331έΗΤ      if (constraint.train_id === train.id) {
  1332έΗΤ        return constraint.description;
  1333έΗΤ      }
  1334έΗΤ    }
  1335έΗΤ    
  1336έΗΤ    // NEW v2.1: Check route compatibility
  1337έΗΤ    if (input.route_compatibility) {
  1338έΗΤ      const incompatible = input.route_compatibility.find(
  1339έΗΤ        c => c.train_id === train.id && 
  1340έΗΤ             c.route_id === route.id && 
  1341έΗΤ             !c.is_compatible
  1342έΗΤ      );
  1343έΗΤ      if (incompatible) {
  1344έΗΤ        return `Route incompatible: ${incompatible.constraint_type} - ${incompatible.restriction_reason || 'Technical restriction'}`;
  1345έΗΤ      }
  1346έΗΤ    }
  1347έΗΤ    
  1348έΗΤ    // Check pending PMs that block assignment
  1349έΗΤ    for (const pm of input.pending_pms) {
  1350έΗΤ      if (pm.train_id === train.id && 
  1351έΗΤ          pm.target_date <= new Date().toISOString().split('T')[0]) {
  1352έΗΤ        // Check if materials are available
  1353έΗΤ        const blocked = pm.required_materials.some(mat => {
  1354έΗΤ          if (mat.criticality !== 'BLOCKING') return false;
  1355έΗΤ          
  1356έΗΤ          const position = input.material_positions.find(
  1357έΗΤ            p => p.part_number === mat.part_number && 
  1358έΗΤ                 p.depot_id === train.home_depot_id
  1359έΗΤ          );
  1360έΗΤ          
  1361έΗΤ          return !position || position.quantity_available < mat.quantity;
  1362έΗΤ        });
  1363έΗΤ        
  1364έΗΤ        if (!blocked) {
  1365έΗΤ          return `PM ${pm.pm_type} due today`;
  1366έΗΤ        }
  1367έΗΤ      }
  1368έΗΤ    }
  1369έΗΤ    
  1370έΗΤ    return null;
  1371έΗΤ  }
  1372έΗΤ}
  1373έΗΤ
  1374έΗΤ// NEW v2.1: Extended optimizer input interface
  1375έΗΤinterface OptimizerInput {
  1376έΗΤ  request_id: string;
  1377έΗΤ  assignment_date: string;
  1378έΗΤ  
