  1456έΗΤ
  1457έΗΤ### 4.3.3 C++ Optimizer Core
  1458έΗΤ
  1459έΗΤ```cpp
  1460έΗΤ// mms-optimizer/src/solver.cpp
  1461έΗΤ
  1462έΗΤ#include <ortools/sat/cp_model.h>
  1463έΗΤ#include <nlohmann/json.hpp>
  1464έΗΤ#include <vector>
  1465έΗΤ#include <unordered_map>
  1466έΗΤ
  1467έΗΤusing namespace operations_research::sat;
  1468έΗΤusing json = nlohmann::json;
  1469έΗΤ
  1470έΗΤstruct ExplanationFactor {
  1471έΗΤ    std::string constraint_type;  // "HARD" or "SOFT"
  1472έΗΤ    std::string constraint_name;
  1473έΗΤ    double impact;
  1474έΗΤ    std::string description;
  1475έΗΤ};
  1476έΗΤ
  1477έΗΤclass MmsSolver {
  1478έΗΤpublic:
  1479έΗΤ    json solve(const json& input) {
  1480έΗΤ        CpModelBuilder model;
  1481έΗΤ        std::string request_id = input["request_id"];
  1482έΗΤ        
  1483έΗΤ        auto trains = input["trains"];
  1484έΗΤ        auto routes = input["routes"];
  1485έΗΤ        auto config = input["config"];
  1486έΗΤ        
  1487έΗΤ        // Decision variables: assign[t][r] = 1 if train t assigned to route r
  1488έΗΤ        std::vector<std::vector<BoolVar>> assign;
  1489έΗΤ        assign.resize(trains.size());
  1490έΗΤ        
  1491έΗΤ        for (size_t t = 0; t < trains.size(); t++) {
  1492έΗΤ            assign[t].resize(routes.size());
  1493έΗΤ            for (size_t r = 0; r < routes.size(); r++) {
  1494έΗΤ                assign[t][r] = model.NewBoolVar();
  1495έΗΤ            }
  1496έΗΤ        }
  1497έΗΤ        
  1498έΗΤ        // Hard constraint: Each train assigned to at most one route
  1499έΗΤ        for (size_t t = 0; t < trains.size(); t++) {
  1500έΗΤ            std::vector<BoolVar> train_routes;
  1501έΗΤ            for (size_t r = 0; r < routes.size(); r++) {
  1502έΗΤ                train_routes.push_back(assign[t][r]);
  1503έΗΤ            }
  1504έΗΤ            model.AddAtMostOne(train_routes);
  1505έΗΤ        }
  1506έΗΤ        
  1507έΗΤ        // Hard constraint: Route requirements (exactly N trains)
  1508έΗΤ        for (size_t r = 0; r < routes.size(); r++) {
  1509έΗΤ            std::vector<BoolVar> route_trains;
  1510έΗΤ            for (size_t t = 0; t < trains.size(); t++) {
  1511έΗΤ                // Check fleet compatibility
  1512έΗΤ                if (isFleetAllowed(trains[t], routes[r])) {
  1513έΗΤ                    route_trains.push_back(assign[t][r]);
  1514έΗΤ                }
  1515έΗΤ            }
  1516έΗΤ            
  1517έΗΤ            int required = routes[r]["required_trains"];
  1518έΗΤ            model.AddEquality(LinearExpr::Sum(route_trains), required);
  1519έΗΤ        }
  1520έΗΤ        
  1521έΗΤ        // Hard constraint: Fitness status
  1522έΗΤ        for (size_t t = 0; t < trains.size(); t++) {
  1523έΗΤ            if (trains[t]["fitness_status"] != "FIT") {
  1524έΗΤ                for (size_t r = 0; r < routes.size(); r++) {
  1525έΗΤ                    model.AddEquality(assign[t][r], 0);
  1526έΗΤ                }
  1527έΗΤ            }
  1528έΗΤ        }
  1529έΗΤ        
  1530έΗΤ        // Hard constraints from input
  1531έΗΤ        for (const auto& constraint : input["hard_constraints"]) {
  1532έΗΤ            size_t train_idx = findTrainIndex(trains, constraint["train_id"]);
  1533έΗΤ            if (train_idx < trains.size()) {
  1534έΗΤ                for (size_t r = 0; r < routes.size(); r++) {
  1535έΗΤ                    model.AddEquality(assign[train_idx][r], 0);
  1536έΗΤ                }
  1537έΗΤ            }
  1538έΗΤ        }
  1539έΗΤ        
  1540έΗΤ        // NEW v2.1: Hard constraint - Unavailability events
  1541έΗΤ        if (input.contains("unavailability_events")) {
  1542έΗΤ            for (const auto& event : input["unavailability_events"]) {
  1543έΗΤ                if (event["status"] == "ACTIVE" && event["blocks_run_assignment"].get<bool>()) {
  1544έΗΤ                    size_t train_idx = findTrainIndex(trains, event["train_id"]);
  1545έΗΤ                    if (train_idx < trains.size()) {
  1546έΗΤ                        for (size_t r = 0; r < routes.size(); r++) {
  1547έΗΤ                            model.AddEquality(assign[train_idx][r], 0);
  1548έΗΤ                        }
  1549έΗΤ                    }
  1550έΗΤ                }
  1551έΗΤ            }
  1552έΗΤ        }
  1553έΗΤ        
  1554έΗΤ        // NEW v2.1: Hard constraint - Route compatibility
  1555έΗΤ        if (input.contains("route_compatibility")) {
  1556έΗΤ            for (const auto& compat : input["route_compatibility"]) {
  1557έΗΤ                if (!compat["is_compatible"].get<bool>()) {
  1558έΗΤ                    size_t train_idx = findTrainIndex(trains, compat["train_id"]);
  1559έΗΤ                    size_t route_idx = findRouteIndex(routes, compat["route_id"]);
  1560έΗΤ                    if (train_idx < trains.size() && route_idx < routes.size()) {
  1561έΗΤ                        model.AddEquality(assign[train_idx][route_idx], 0);
  1562έΗΤ                    }
  1563έΗΤ                }
  1564έΗΤ            }
  1565έΗΤ        }
  1566έΗΤ        
  1567έΗΤ        // Soft constraint: Mileage balance
  1568έΗΤ        std::vector<IntVar> mileage_penalties;
  1569έΗΤ        auto penalties = config["soft_constraint_penalties"];
  1570έΗΤ        int mileage_weight = penalties["mileage_imbalance"].get<int>();
  1571έΗΤ        
  1572έΗΤ        for (size_t t = 0; t < trains.size(); t++) {
  1573έΗΤ            int current = trains[t]["current_mileage"];
  1574έΗΤ            int target = trains[t]["target_mileage"];
  1575έΗΤ            int variance = std::abs(current - target);
  1576έΗΤ            
  1577έΗΤ            for (size_t r = 0; r < routes.size(); r++) {
  1578έΗΤ                int route_km = routes[r]["expected_km"];
  1579έΗΤ                
  1580έΗΤ                // Penalty for assigning over-utilized train to high-km route
  1581έΗΤ                if (current > target && route_km > 200) {
  1582έΗΤ                    IntVar penalty = model.NewIntVar({0, variance * mileage_weight});
  1583έΗΤ                    model.AddEquality(penalty, variance * mileage_weight)
  1584έΗΤ                        .OnlyEnforceIf(assign[t][r]);
  1585έΗΤ                    model.AddEquality(penalty, 0)
  1586έΗΤ                        .OnlyEnforceIf(assign[t][r].Not());
  1587έΗΤ                    mileage_penalties.push_back(penalty);
  1588έΗΤ                }
  1589έΗΤ            }
  1590έΗΤ        }
  1591έΗΤ        
  1592έΗΤ        // Objective: Minimize total penalty
  1593έΗΤ        model.Minimize(LinearExpr::Sum(mileage_penalties));
  1594έΗΤ        
  1595έΗΤ        // Solve
  1596έΗΤ        SatParameters params;
  1597έΗΤ        params.set_max_time_in_seconds(
  1598έΗΤ            config["max_solve_time_seconds"].get<double>()
  1599έΗΤ        );
  1600έΗΤ        params.set_num_search_workers(
  1601έΗΤ            config["num_workers"].get<int>()
  1602έΗΤ        );
  1603έΗΤ        
  1604έΗΤ        Model cp_model;
  1605έΗΤ        cp_model.Add(NewSatParameters(params));
  1606έΗΤ        
  1607έΗΤ        // Progress callback
  1608έΗΤ        int callback_count = 0;
  1609έΗΤ        cp_model.Add(NewFeasibleSolutionObserver([&](const CpSolverResponse& r) {
  1610έΗΤ            callback_count++;
  1611έΗΤ            if (callback_count % 5 == 0) {
  1612έΗΤ                emitProgress(request_id, 
  1613έΗΤ                    std::min(90.0, callback_count * 3.0),
  1614έΗΤ                    r.objective_value(), true);
  1615έΗΤ            }
  1616έΗΤ        }));
  1617έΗΤ        
  1618έΗΤ        CpSolverResponse response = SolveCpModel(model.Build(), &cp_model);
  1619έΗΤ        
  1620έΗΤ        // Build result
  1621έΗΤ        json result;
  1622έΗΤ        result["type"] = "RESULT";
  1623έΗΤ        result["request_id"] = request_id;
  1624έΗΤ        result["solve_time_ms"] = response.wall_time() * 1000;
  1625έΗΤ        
  1626έΗΤ        if (response.status() == CpSolverStatus::OPTIMAL ||
  1627έΗΤ            response.status() == CpSolverStatus::FEASIBLE) {
  1628έΗΤ            
  1629έΗΤ            result["status"] = response.status() == CpSolverStatus::OPTIMAL 
  1630έΗΤ                ? "OPTIMAL" : "FEASIBLE";
  1631έΗΤ            
  1632έΗΤ            json assignments = json::array();
  1633έΗΤ            
  1634έΗΤ            for (size_t t = 0; t < trains.size(); t++) {
  1635έΗΤ                for (size_t r = 0; r < routes.size(); r++) {
  1636έΗΤ                    if (SolutionBooleanValue(response, assign[t][r])) {
  1637έΗΤ                        json assignment;
  1638έΗΤ                        assignment["train_id"] = trains[t]["id"];
  1639έΗΤ                        assignment["route_id"] = routes[r]["id"];
  1640έΗΤ                        assignment["score"] = computeScore(trains[t], routes[r], response);
  1641έΗΤ                        assignment["explanation"] = generateExplanation(
  1642έΗΤ                            trains[t], routes[r], input, response
  1643έΗΤ                        );
  1644έΗΤ                        assignments.push_back(assignment);
  1645έΗΤ                    }
  1646έΗΤ                }
  1647έΗΤ            }
  1648έΗΤ            
  1649έΗΤ            result["assignments"] = assignments;
  1650έΗΤ            result["unassigned"] = findUnassigned(trains, assignments, input);
  1651έΗΤ            result["material_warnings"] = checkMaterialWarnings(input);
  1652έΗΤ            result["summary"] = buildSummary(response, assignments);
  1653έΗΤ            
  1654έΗΤ        } else {
  1655έΗΤ            result["status"] = "INFEASIBLE";
  1656έΗΤ            result["assignments"] = json::array();
  1657έΗΤ            result["unassigned"] = json::array();
  1658έΗΤ            result["summary"] = {
  1659έΗΤ                {"total_penalty", -1},
  1660έΗΤ                {"trains_assigned", 0},
  1661έΗΤ                {"trains_unassigned", trains.size()}
  1662έΗΤ            };
  1663έΗΤ        }
  1664έΗΤ        
  1665έΗΤ        return result;
  1666έΗΤ    }
  1667έΗΤ    
  1668έΗΤprivate:
  1669έΗΤ    json generateExplanation(
  1670έΗΤ        const json& train,
  1671έΗΤ        const json& route,
  1672έΗΤ        const json& input,
  1673έΗΤ        const CpSolverResponse& response
  1674έΗΤ    ) {
  1675έΗΤ        json factors = json::array();
  1676έΗΤ        
  1677έΗΤ        // Mileage balance factor
  1678έΗΤ        int current = train["current_mileage"];
  1679έΗΤ        int target = train["target_mileage"];
  1680έΗΤ        int variance = current - target;
  1681έΗΤ        
  1682έΗΤ        factors.push_back({
  1683έΗΤ            {"constraint_type", "SOFT"},
  1684έΗΤ            {"constraint_name", "MILEAGE_BALANCE"},
  1685έΗΤ            {"impact", std::abs(variance)},
  1686έΗΤ            {"description", fmt::format(
  1687έΗΤ                "Train is {}km {} fleet target",
  1688έΗΤ                std::abs(variance),
  1689έΗΤ                variance < 0 ? "under" : "over"
  1690έΗΤ            )}
  1691έΗΤ        });
  1692έΗΤ        
  1693έΗΤ        // Route match factor
  1694έΗΤ        int route_km = route["expected_km"];
  1695έΗΤ        std::string route_advice = "";
  1696έΗΤ        
  1697έΗΤ        if (variance < -1000 && route_km > 300) {
  1698έΗΤ            route_advice = "High-km route helps balance under-utilized train";
  1699έΗΤ        } else if (variance > 1000 && route_km < 150) {
  1700έΗΤ            route_advice = "Low-km route reduces over-utilization";
  1701έΗΤ        }
